from typing import Annotated
from pydantic import Field
from agents import function_tool

@function_tool
def search_documents(
    query: Annotated[str, Field(description="Full-text search query")],
    max_results: Annotated[int, Field(description="Maximum number of results", ge=1, le=20)] = 5,
) -> list[dict]:
    """Search an internal document store."""
    return [{"title": f"Result {i}", "score": 0.9 - i * 0.1} for i in range(max_results)]

from agents import Agent, Runner, input_guardrail, output_guardrail, GuardrailFunctionOutput

@input_guardrail
async def no_pii(ctx, agent, input) -> GuardrailFunctionOutput:
    text = input if isinstance(input, str) else str(input)
    if "@" in text:
        return GuardrailFunctionOutput(
            output_info="PII detected",
            tripwire_triggered=True,
        )
    return GuardrailFunctionOutput(tripwire_triggered=False)

@output_guardrail
async def no_code_in_response(ctx, agent, output) -> GuardrailFunctionOutput:
    if "```" in str(output):
        return GuardrailFunctionOutput(
            output_info="Unexpected code block in output",
            tripwire_triggered=True,
        )
    return GuardrailFunctionOutput(tripwire_triggered=False)

safe_agent = Agent(
    name="SafeAgent",
    instructions="Answer questions concisely.",
    input_guardrails=[no_pii],
    output_guardrails=[no_code_in_response],
)

